CREATE TABLE IF NOT EXISTS users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(190) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role ENUM('customer','super_admin','store_manager','sales','stock_manager','delivery_manager','support','accountant') NOT NULL DEFAULT 'customer',status ENUM('active','blocked') NOT NULL DEFAULT 'active',last_login_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS categories (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,slug VARCHAR(140) NOT NULL UNIQUE,description TEXT NULL,image_path VARCHAR(255) NULL,seo_title VARCHAR(190) NULL,seo_description VARCHAR(300) NULL,is_active BOOLEAN NOT NULL DEFAULT TRUE,sort_order INT NOT NULL DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS schools (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(160) NOT NULL,slug VARCHAR(180) NOT NULL UNIQUE,location VARCHAR(160) NULL,school_type VARCHAR(80) NULL,description TEXT NULL,logo_path VARCHAR(255) NULL,is_featured BOOLEAN NOT NULL DEFAULT FALSE,is_active BOOLEAN NOT NULL DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS products (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,category_id BIGINT UNSIGNED NULL,school_id BIGINT UNSIGNED NULL,name VARCHAR(190) NOT NULL,slug VARCHAR(210) NOT NULL UNIQUE,sku VARCHAR(80) NOT NULL UNIQUE,brand VARCHAR(120) NULL,product_type VARCHAR(120) NULL,gender VARCHAR(30) NULL,age_group VARCHAR(40) NULL,material VARCHAR(160) NULL,google_product_category VARCHAR(190) NULL,source_url VARCHAR(500) NULL,short_description VARCHAR(300) NULL,description TEXT NULL,price DECIMAL(12,2) NOT NULL,compare_price DECIMAL(12,2) NULL,stock INT UNSIGNED NOT NULL DEFAULT 0,status ENUM('draft','active','archived') NOT NULL DEFAULT 'draft',is_featured BOOLEAN NOT NULL DEFAULT FALSE,is_new BOOLEAN NOT NULL DEFAULT FALSE,seo_title VARCHAR(190) NULL,seo_description VARCHAR(300) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,CONSTRAINT fk_product_category FOREIGN KEY(category_id) REFERENCES categories(id) ON DELETE SET NULL,CONSTRAINT fk_product_school FOREIGN KEY(school_id) REFERENCES schools(id) ON DELETE SET NULL,INDEX idx_product_catalog(status,category_id,school_id),FULLTEXT INDEX ft_product(name,short_description,description)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS product_images (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,product_id BIGINT UNSIGNED NOT NULL,image_path VARCHAR(500) NOT NULL,alt_text VARCHAR(190) NULL,source_url VARCHAR(500) NULL,license_name VARCHAR(120) NULL,credit_text VARCHAR(255) NULL,sort_order INT NOT NULL DEFAULT 0,CONSTRAINT fk_image_product FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS hero_images (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,image_path VARCHAR(500) NOT NULL,mobile_image_path VARCHAR(500) NULL,alt_text VARCHAR(190) NULL,sort_order INT NOT NULL DEFAULT 0,is_active BOOLEAN NOT NULL DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX idx_hero_active(is_active,sort_order)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS product_variants (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,product_id BIGINT UNSIGNED NOT NULL,size VARCHAR(80) NOT NULL DEFAULT '',colour VARCHAR(80) NOT NULL DEFAULT '',sku VARCHAR(100) NOT NULL UNIQUE,stock INT UNSIGNED NOT NULL DEFAULT 0,low_stock_level INT UNSIGNED NOT NULL DEFAULT 5,price_adjustment DECIMAL(12,2) NOT NULL DEFAULT 0,is_active BOOLEAN NOT NULL DEFAULT TRUE,CONSTRAINT fk_variant_product FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE,UNIQUE KEY uq_variant(product_id,size,colour)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS checkout_methods (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,code VARCHAR(40) NOT NULL UNIQUE,name VARCHAR(100) NOT NULL,instructions TEXT NULL,config_json JSON NULL,is_enabled BOOLEAN NOT NULL DEFAULT FALSE,is_default BOOLEAN NOT NULL DEFAULT FALSE,sort_order INT NOT NULL DEFAULT 0,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS orders (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,order_number VARCHAR(32) NOT NULL UNIQUE,user_id BIGINT UNSIGNED NULL,customer_name VARCHAR(120) NOT NULL,email VARCHAR(190) NOT NULL,phone VARCHAR(40) NOT NULL,delivery_method VARCHAR(80) NOT NULL,delivery_address TEXT NULL,checkout_method VARCHAR(40) NOT NULL,status ENUM('pending_payment','paid','processing','awaiting_personalisation','ready_dispatch','dispatched','ready_pickup','delivered','completed','cancelled','refunded') NOT NULL DEFAULT 'pending_payment',payment_status ENUM('pending','paid','failed','refunded') NOT NULL DEFAULT 'pending',subtotal DECIMAL(12,2) NOT NULL,delivery_fee DECIMAL(12,2) NOT NULL DEFAULT 0,total DECIMAL(12,2) NOT NULL,notes TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,CONSTRAINT fk_order_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL,INDEX idx_orders_status(status,created_at)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS order_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,order_id BIGINT UNSIGNED NOT NULL,product_id BIGINT UNSIGNED NULL,variant_id BIGINT UNSIGNED NULL,product_name VARCHAR(190) NOT NULL,sku VARCHAR(100) NOT NULL,size VARCHAR(80) NULL,colour VARCHAR(80) NULL,quantity INT UNSIGNED NOT NULL,unit_price DECIMAL(12,2) NOT NULL,line_total DECIMAL(12,2) NOT NULL,CONSTRAINT fk_item_order FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,CONSTRAINT fk_item_product FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE SET NULL,CONSTRAINT fk_item_variant FOREIGN KEY(variant_id) REFERENCES product_variants(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS settings (setting_key VARCHAR(100) PRIMARY KEY,setting_value TEXT NULL,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS audit_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NULL,action VARCHAR(120) NOT NULL,entity_type VARCHAR(80) NULL,entity_id BIGINT UNSIGNED NULL,ip_address VARCHAR(64) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_audit_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL,INDEX idx_audit(created_at,user_id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS password_reset_tokens (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NOT NULL,token_hash CHAR(64) NOT NULL UNIQUE,expires_at DATETIME NOT NULL,used_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_reset_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,INDEX idx_reset_expiry(expires_at)) ENGINE=InnoDB;
INSERT IGNORE INTO checkout_methods(code,name,instructions,is_enabled,sort_order) VALUES ('whatsapp','Order via WhatsApp','Review your order, then continue securely in WhatsApp.',FALSE,10),('mpesa','M-Pesa','Payment instructions will appear after order confirmation.',FALSE,20),('bank','Bank transfer','Bank details will appear after order confirmation.',FALSE,30),('pickup','Pay on pickup','Pay when collecting your order.',FALSE,40),('cod','Cash on delivery','Available only for approved delivery areas.',FALSE,50);
